export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export enum ScanMode {
  INTERACTIVE = 'INTERACTIVE',
  BATCH = 'BATCH'
}

export interface Tag {
  epc: string;
  timestamp: number;
  rssi?: number;
  count: number;
}

export interface Settings {
  power: number;
  frequency: string;
  rfParams: string; // "speed,qv,session,target"
  buzzer: boolean;
  deviceInfo: string;
}

export interface BleError {
  message: string;
  timestamp: number;
}

export type LogEntry = {
  type: 'info' | 'error' | 'rx' | 'tx';
  message: string;
  timestamp: number;
};

export type WriteStatus = 'idle' | 'pending' | 'success' | 'error';

// Internal types for component props
export interface ControlsProps {
  status: ConnectionStatus;
  scanMode: ScanMode;
  isScanning: boolean;
  settings: Settings;
  onConnect: () => void;
  onDisconnect: () => void;
  onToggleMode: (mode: ScanMode) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  onUpdateSettings: (key: keyof Settings, value: string | number | boolean) => void;
}

export interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export interface BatchResultsProps {
  fileContent: string;
  transferProgress: number; // 0-100, -1 if idle
  isTransferring: boolean;
  onRequestFile: () => void;
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = 'inline-flex items-center justify-center rounded-lg font-medium transition-all duration-300 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed tracking-widest uppercase active:scale-95 focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-cyan-500 focus-visible:ring-offset-ui-bg';

  const variants = {
    // High Contrast White (Primary Action)
    primary: 'bg-white text-zinc-950 hover:bg-zinc-200 hover:shadow-[0_0_20px_rgba(255,255,255,0.4)] border border-transparent',

    // Matte Dark (Secondary)
    secondary: 'bg-zinc-800 text-zinc-300 hover:bg-zinc-700 hover:text-white border border-zinc-700',

    // Danger Red (Alert/Stop)
    danger: 'bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white border border-red-500/50 hover:border-red-500 hover:shadow-[0_0_15px_rgba(239,68,68,0.4)]',

    // Success Cyan (Start/Active)
    success: 'bg-cyan-500/10 text-cyan-400 hover:bg-cyan-400 hover:text-zinc-950 border border-cyan-500/50 hover:border-cyan-400 hover:shadow-[0_0_15px_rgba(34,211,238,0.4)]',

    // Outline
    outline: 'border border-zinc-600 text-zinc-400 hover:border-white hover:text-white bg-transparent',

    // Ghost
    ghost: 'text-zinc-500 hover:text-white hover:bg-zinc-800'
  };

  const sizes = {
    sm: 'px-4 py-1.5 text-[10px] font-bold',
    md: 'px-6 py-2.5 text-xs font-bold',
    lg: 'px-8 py-4 text-sm font-bold'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';

interface SwitchProps {
  checked: boolean;
  onChange: (checked: boolean) => void;
  disabled?: boolean;
}

export const Switch: React.FC<SwitchProps> = ({ checked, onChange, disabled }) => {
  return (
    <button
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      disabled={disabled}
      className={`relative inline-flex h-7 w-12 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-cyan-500 focus:ring-offset-2 focus:ring-offset-zinc-900 disabled:cursor-not-allowed disabled:opacity-50 ${
        checked ? 'bg-cyan-600' : 'bg-zinc-700'
      }`}
    >
      <span
        aria-hidden="true"
        className={`inline-block h-6 w-6 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${
          checked ? 'translate-x-5' : 'translate-x-0'
        }`}
      />
    </button>
  );
};

import React from 'react';
import { Minus, Plus } from 'lucide-react';

interface StepperProps {
  value: number;
  onChange: (value: number) => void;
  min?: number;
  max?: number;
  step?: number;
  disabled?: boolean;
}

export const Stepper: React.FC<StepperProps> = ({
  value,
  onChange,
  min = 0,
  max = 100,
  step = 1,
  disabled = false,
}) => {
  const handleIncrement = () => {
    if (disabled) return;
    const newValue = Math.min(max, value + step);
    onChange(newValue);
  };

  const handleDecrement = () => {
    if (disabled) return;
    const newValue = Math.max(min, value - step);
    onChange(newValue);
  };

  return (
    <div className="flex items-center justify-between bg-zinc-900 p-1 rounded-full border border-zinc-800 h-12">
      <button
        onClick={handleDecrement}
        disabled={disabled || value <= min}
        className="w-12 h-full flex items-center justify-center text-zinc-400 hover:text-white rounded-full hover:bg-zinc-800 disabled:opacity-50 active:scale-90 transition-all"
      >
        <Minus size={16} />
      </button>
      <div className="flex-1 text-center font-mono text-lg font-bold text-white">
        {value}
      </div>
      <button
        onClick={handleIncrement}
        disabled={disabled || value >= max}
        className="w-12 h-full flex items-center justify-center text-zinc-400 hover:text-white rounded-full hover:bg-zinc-800 disabled:opacity-50 active:scale-90 transition-all"
      >
        <Plus size={16} />
      </button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Bluetooth, Radio, Play, Square, Wifi, Volume2, Zap, ChevronDown, ChevronUp, Database } from 'lucide-react';
import { Button } from './ui/Button';
import { Logo } from './ui/Logo';
import { Stepper } from './ui/Stepper';
import { Switch } from './ui/Switch';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
