  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);

  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  const [showRfSettings, setShowRfSettings] = useState(false);

  useEffect(() => { setLocalPower(settings.power); }, [settings.power]);
  useEffect(() => { setLocalFreq(settings.frequency); }, [settings.frequency]);
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) { setRfSpeed(parts[0]); setRfQv(parts[1]); setRfSession(parts[2]); setRfTarget(parts[3]); }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isRfDirty = `${rfSpeed},${rfQv},${rfSession},${rfTarget}` !== settings.rfParams;

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar p-6 gap-8 bg-transparent text-zinc-100">

      {/* 1. Header with Brand */}
      <div className="hidden lg:flex items-center justify-between mb-2 opacity-80">
         <div className="flex items-center gap-3 select-none">
            <Logo className="w-6 h-6 text-white" />
            <div className="font-sans">
                <div className="text-sm font-bold text-white leading-none tracking-widest uppercase">Next<span className="text-cyan-400">waves</span></div>
                <div className="text-[10px] text-zinc-500 uppercase tracking-widest font-semibold mt-0.5">Control Unit</div>
            </div>
         </div>
      </div>

      {/* 2. Device Card */}
      <div className="relative w-full bg-zinc-900 rounded-2xl p-6 flex flex-col gap-6 group transition-all border border-zinc-800 shadow-xl overflow-hidden">
          <div className={`absolute top-0 right-0 w-64 h-64 bg-cyan-500/10 blur-[80px] rounded-full pointer-events-none transition-opacity duration-1000 ${isConnected ? 'opacity-100' : 'opacity-0'}`}></div>

          <div className="flex justify-between items-start relative z-10">
              <div>
                  <h2 className="text-[11px] font-bold text-zinc-500 uppercase tracking-widest mb-1">System State</h2>
                  <div className="flex items-center gap-2">
                      <div className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-cyan-400 shadow-[0_0_8px_#22d3ee]' : 'bg-zinc-700'}`}></div>
                      <span className={`text-xl font-bold tracking-tighter ${isConnected ? 'text-white' : 'text-zinc-500'}`}>
                          {status === ConnectionStatus.CONNECTED ? 'ONLINE' : status === ConnectionStatus.CONNECTING ? 'SYNCING...' : 'OFFLINE'}
                      </span>
                  </div>
              </div>
              <div className={`p-2 rounded-full border ${isConnected ? 'bg-cyan-950/30 border-cyan-500/30 text-cyan-400' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>
                  <Bluetooth size={18} />
              </div>
          </div>

          {isConnected ? (
              <div className="grid grid-cols-2 gap-3 relative z-10">
                  <div className="bg-zinc-950/50 p-4 rounded-xl border border-zinc-800 flex flex-col justify-center">
                      <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-1">Battery</span>
                      <span className="text-sm font-mono text-emerald-400 font-bold shadow-emerald-500/20 drop-shadow-sm">100%</span>
                  </div>
                  <div className="bg-zinc-950/50 p-4 rounded-xl border border-zinc-800 flex flex-col justify-center min-w-0">
                      <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-1">Unit ID</span>
                      <span className="text-[10px] font-mono text-zinc-300 font-bold break-all leading-tight">
                          {settings.deviceInfo || 'V3-Unknown'}
                      </span>
                  </div>
              </div>
          ) : (
             <div className="py-2 relative z-10">
                <Button fullWidth variant="primary" onClick={onConnect} disabled={status === ConnectionStatus.CONNECTING} className="shadow-[0_0_20px_rgba(255,255,255,0.1)] rounded-full">
                    {status === ConnectionStatus.CONNECTING ? 'Initialising...' : 'Connect Scanner'}
                </Button>
             </div>
          )}

          {isConnected && (
             <button onClick={onDisconnect} disabled={isScanning} className="relative z-10 text-[10px] text-zinc-600 hover:text-red-400 font-bold uppercase tracking-widest text-center transition-colors">
                Terminate Connection
             </button>
          )}
      </div>

      {/* 3. Operation Modes */}
      <div className="space-y-4">
          <label className="text-[11px] font-bold text-zinc-500 uppercase tracking-widest ml-1">Operation Mode</label>
          <div className="bg-zinc-900/70 p-1 rounded-xl flex relative border border-zinc-800">
              <button 
                  onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
                  disabled={isScanning}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-[10px] font-bold tracking-wider transition-all duration-300 ${scanMode === ScanMode.INTERACTIVE ? 'bg-white text-zinc-950 shadow-md shadow-black/20' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                  <Radio size={12} />
                  <span>LIVE</span>
              </button>
              <button 
                  onClick={() => onToggleMode(ScanMode.BATCH)}
                  disabled={isScanning}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-[10px] font-bold tracking-wider transition-all duration-300 ${scanMode === ScanMode.BATCH ? 'bg-white text-zinc-950 shadow-md shadow-black/20' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                  <Database size={12} />
                  <span>BATCH</span>
              </button>
          </div>

          <Button 
             variant={isScanning ? 'danger' : 'success'} 
             fullWidth 
             size="lg"
             onClick={isScanning ? onStopScan : onStartScan}
             disabled={!isConnected}
             className="mt-4 shadow-xl rounded-full"
          >
             {isScanning ? (
                <div className="flex items-center gap-3"><Square size={16} fill="currentColor" /> STOP SEQUENCE</div>
             ) : (
                <div className="flex items-center gap-3"><Play size={16} fill="currentColor" /> INITIATE SCAN</div>
             )}
          </Button>
      </div>

      {/* 4. Settings */}
      <div className="space-y-6 pt-6 border-t border-zinc-800/50">

          <div>
              <div className="flex justify-between items-center mb-4 px-1">
                  <div className="flex items-center gap-2 text-zinc-400">
                      <Wifi size={14} />
                      <span className="text-[11px] font-bold uppercase tracking-widest">Signal Output</span>
                  </div>
                  <span className={`text-sm font-mono font-bold ${isPowerDirty ? 'text-cyan-400' : 'text-white'}`}>{localPower} <span className="text-[10px] text-zinc-600 font-sans">dBm</span></span>
              </div>
              <Stepper
                value={localPower}
                onChange={setLocalPower}
                min={0}
                max={33}
                disabled={!isConnected || isScanning}
              />
              {isPowerDirty && (
                 <div className="mt-3 text-right">
                    <button onClick={() => onUpdateSettings('power', localPower)} className="text-[10px] font-bold text-cyan-400 hover:text-cyan-300 tracking-wider uppercase">Apply Change</button>
                 </div>
              )}
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                  <label className="text-[11px] uppercase font-bold text-zinc-600 ml-1 tracking-widest">Frequency</label>
                  <div className="relative">
                      <select 
                        className="w-full bg-zinc-900 text-zinc-300 text-[10px] font-bold py-3 px-4 rounded-xl appearance-none outline-none border border-zinc-800 focus:border-cyan-500 transition-colors"
                        value={localFreq}
                        onChange={(e) => setLocalFreq(e.target.value)}
                        disabled={!isConnected || isScanning}
                      >
                          <option value="US">US FCC</option>
                          <option value="EU">EU ETSI</option>
                          <option value="CN">CHINA</option>
                          <option value="VN">VIETNAM</option>
                      </select>
                      <ChevronDown size={14} className="absolute right-3 top-3.5 text-zinc-600 pointer-events-none" />
                  </div>
                  {isFreqDirty && <button onClick={() => onUpdateSettings('frequency', localFreq)} className="text-[10px] text-cyan-400 font-bold block w-full text-right mt-1 uppercase">Save</button>}
              </div>

              <div className="space-y-2">
                  <label className="text-[11px] uppercase font-bold text-zinc-600 ml-1 tracking-widest">Audio Feed</label>
                   <div className='flex items-center gap-3 bg-zinc-900 p-2 rounded-xl border border-zinc-800 h-[46px]'>
                        <Volume2 size={16} className={settings.buzzer ? 'text-zinc-300' : 'text-zinc-600'} />
                        <span className="text-xs font-bold text-zinc-400">{settings.buzzer ? 'ENABLED' : 'MUTED'}</span>
                        <div className="flex-1 flex justify-end">
                             <Switch
                                checked={settings.buzzer}
                                onChange={(val) => onUpdateSettings('buzzer', val)}
                                disabled={!isConnected || isScanning}
                            />
                        </div>
                   </div>
              </div>
          </div>

           <div>
                <button 
                    onClick={() => setShowRfSettings(!showRfSettings)}
                    className="group w-full flex items-center justify-between text-[10px] uppercase font-bold tracking-widest py-3 px-2 rounded-lg text-zinc-500 hover:text-zinc-300 transition-colors"
                >
                    <div className="flex items-center gap-2">
                        <Zap size={12} className={isRfDirty ? "text-cyan-500 fill-current" : "text-zinc-600 group-hover:text-zinc-400"} />
                        <span className={isRfDirty ? "text-cyan-500" : ""}>Advanced RF Config</span>
                    </div>
                    {showRfSettings ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
                </button>

                {showRfSettings && (
                    <div className="bg-zinc-900/50 rounded-2xl p-5 mt-2 space-y-4 animate-in slide-in-from-top-1 duration-200 border border-zinc-800/50">
                        <div className="grid grid-cols-2 gap-4">
                            {[
                                { label: 'Link Profile', val: rfSpeed, set: setRfSpeed, opts: [{v:0, l:'M0 (40K)'}, {v:1, l:'M4 (250K)'}, {v:2, l:'M4 (300K)'}, {v:3, l:'M0 (400K)'}] },
                                { label: 'Q Factor', val: rfQv, set: setRfQv, opts: [...Array(16)].map((_, i) => ({v:i, l:`Q = ${i}`})) },
                                { label: 'Session', val: rfSession, set: setRfSession, opts: [{v:0, l:'S0 (Fast)'}, {v:1, l:'S1 (A)'}, {v:2, l:'S2 (B)'}, {v:3, l:'S3 (Long)'}] },
                                { label: 'Target', val: rfTarget, set: setRfTarget, opts: [{v:0, l:'A'}, {v:1, l:'B'}, {v:2, l:'A/B'}] }
                            ].map((item, idx) => (
                                <div key={idx} className="space-y-1">
                                    <label className="text-[10px] text-zinc-500 uppercase font-bold">{item.label}</label>
                                    <div className="relative">
                                        <select 
                                            className="w-full bg-zinc-950 text-zinc-300 text-[10px] font-bold py-2 pl-2 pr-6 rounded-lg border border-zinc-800 focus:border-cyan-500 appearance-none outline-none"
                                            value={item.val}
                                            onChange={(e) => item.set(parseInt(e.target.value))}
                                            disabled={!isConnected || isScanning}
                                        >
                                            {item.opts.map((opt: any) => <option key={opt.v} value={opt.v}>{opt.l}</option>)}
                                        </select>
                                        <ChevronDown size={10} className="absolute right-2 top-2.5 text-zinc-600 pointer-events-none" />
                                    </div>
                                </div>
                            ))}
                        </div>

                        <Button 
                            fullWidth 
                            size="sm" 
                            variant={isRfDirty ? 'primary' : 'secondary'}
                            disabled={!isConnected || isScanning || !isRfDirty}
                            onClick={() => onUpdateSettings('rfParams', `${rfSpeed},${rfQv},${rfSession},${rfTarget}`)}
                            className="rounded-xl mt-2"
                        >
                            {isRfDirty ? 'Sync Configuration' : 'Config Synced'}
                        </Button>
                    </div>
                )}
           </div>
      </div>
    </div>
  );
};

