                {showRfSettings && (
                    <div className="bg-slate-100/50 dark:bg-zinc-900/50 rounded-2xl p-5 mt-2 space-y-4 animate-in slide-in-from-top-1 duration-200 border border-slate-200 dark:border-zinc-800/50">
                        <div className="grid grid-cols-2 gap-4">
                            {[
                                { label: 'Link Profile', val: rfSpeed, set: setRfSpeed, opts: [{v:0, l:'M0 (40K)'}, {v:1, l:'M4 (250K)'}, {v:2, l:'M4 (300K)'}, {v:3, l:'M0 (400K)'}] },
                                { label: 'Q Factor', val: rfQv, set: setRfQv, opts: [...Array(16)].map((_, i) => ({v:i, l:`Q = ${i}`})) },
                                { label: 'Session', val: rfSession, set: setRfSession, opts: [{v:0, l:'S0 (Fast)'}, {v:1, l:'S1 (A)'}, {v:2, l:'S2 (B)'}, {v:3, l:'S3 (Long)'}] },
                                { label: 'Target', val: rfTarget, set: setRfTarget, opts: [{v:0, l:'A'}, {v:1, l:'B'}, {v:2, l:'A/B'}] }
                            ].map((item, idx) => (
                                <div key={idx} className="space-y-1">
                                    <label className="text-[10px] text-slate-500 dark:text-zinc-500 uppercase font-bold">{item.label}</label>
                                    <div className="relative">
