                                            value={item.val}
                                            onChange={(e) => item.set(parseInt(e.target.value))}
                                            disabled={!isConnected || isScanning}
                                        >
                                            {item.opts.map((opt: any) => <option key={opt.v} value={opt.v}>{opt.l}</option>)}
                                        </select>
                                        <ChevronDown size={10} className="absolute right-2 top-2.5 text-slate-400 dark:text-zinc-600 pointer-events-none" />
                                    </div>
                                </div>
                            ))}
                        </div>

                        <Button 
                            fullWidth 
                            size="sm" 
                            variant={isRfDirty ? 'primary' : 'secondary'}
                            disabled={!isConnected || isScanning || !isRfDirty}
                            onClick={() => onUpdateSettings('rfParams', `${rfSpeed},${rfQv},${rfSession},${rfTarget}`)}
                            className="rounded-xl mt-2"
