                                        >
                                            <div className="flex items-center gap-4">
                                                <div className="w-1.5 h-1.5 rounded-full bg-cyan-500 shadow-[0_0_8px_#22d3ee]" />
                                                <div>
                                                    <p className="font-mono text-slate-700 dark:text-zinc-300 font-medium group-hover:text-slate-900 dark:group-hover:text-white transition-colors text-sm">{tag.epc}</p>
                                                    <p className="text-[9px] text-slate-400 dark:text-zinc-600 mt-1 font-mono">RSSI: {tag.rssi} dBm</p>
                                                </div>
                                            </div>
                                            <div className="opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0 duration-300">
                                                <span className="text-[9px] bg-cyan-500/10 dark:bg-cyan-950 text-cyan-600 dark:text-cyan-400 border border-cyan-500/20 dark:border-cyan-900/50 px-3 py-1 rounded font-bold uppercase shadow-[0_0_10px_rgba(34,211,238,0.2)]">Initialize</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Step 2: Write */}
            {step === 2 && (
                <div className="flex flex-col gap-8 animate-in slide-in-from-right-4 duration-300 fade-in">
                     <div className="flex items-center gap-4">
                         <div className="flex items-center justify-center w-8 h-8 rounded bg-slate-200 dark:bg-zinc-800 text-slate-800 dark:text-white font-bold border border-slate-300 dark:border-zinc-700 text-sm">2</div>
                         <h3 className="text-slate-900 dark:text-white font-bold text-xs uppercase tracking-wider">Program Data</h3>
                     </div>

                     <div className="bg-white/30 dark:bg-zinc-900/30 border border-slate-200 dark:border-zinc-800 rounded-xl p-8 space-y-10 shadow-2xl backdrop-blur-sm">

                         <div className="grid gap-8">
                            <div className="space-y-2">
                                <label className="text-[9px] text-slate-500 dark:text-zinc-500 uppercase font-bold tracking-widest">Target Identifier</label>
                                <div className="bg-slate-100 dark:bg-zinc-950 border border-slate-200 dark:border-zinc-800 rounded-lg p-4 flex items-center gap-3">
                                    <Database className="w-4 h-4 text-slate-400 dark:text-zinc-600" />
                                    <span className="font-mono text-slate-500 dark:text-zinc-400 text-sm tracking-wider">{targetEpc}</span>
                                </div>
                            </div>

                            <div className="flex justify-center">
                                <div className="bg-slate-100 dark:bg-zinc-900 p-2 rounded-full border border-slate-200 dark:border-zinc-800 shadow-inner">
                                    <ArrowRight className="w-4 h-4 text-cyan-500 animate-pulse" />
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="text-[9px] text-cyan-600 dark:text-cyan-500 uppercase font-bold tracking-widest">New Payload (Hex)</label>
                                <Input 
                                    value={newEpc}
                                    onChange={(e) => {
                                        setNewEpc(e.target.value.toUpperCase());
                                        setError('');
                                    }}
                                    error={error}
                                    className="font-mono text-xl py-4 border-slate-300 dark:border-zinc-700 bg-slate-100 dark:bg-black/50 focus:border-cyan-500 text-center tracking-widest text-slate-900 dark:text-white shadow-inner"
                                    placeholder="0000..."
                                    disabled={writeStatus === 'pending' || writeStatus === 'success'}
                                    autoFocus
                                />
                                <div className="flex justify-between text-[9px] text-slate-400 dark:text-zinc-600 px-1 font-mono">
                                    <span>LEN: {newEpc.length} CHARS</span>
                                    <span>SIZE: {newEpc.length * 4} BITS</span>
                                </div>
                            </div>
                         </div>

                         {/* Actions */}
                         <div className="flex items-center gap-4 pt-6 border-t border-slate-200 dark:border-zinc-800">
                            <Button variant="outline" onClick={handleBackToScan} disabled={writeStatus === 'pending'} size="lg">
                                CANCEL
                            </Button>

                            {writeStatus !== 'success' && (
                                <Button 
                                    variant="primary" 
                                    onClick={validateAndWrite} 
                                    disabled={writeStatus === 'pending'}
                                    size="lg"
                                    className="flex-1 shadow-lg dark:shadow-[0_0_20px_rgba(255,255,255,0.15)]"
                                >
                                    {writeStatus === 'pending' ? 'PROGRAMMING...' : 'EXECUTE WRITE'}
                                </Button>
                            )}
                         </div>

                         {/* Status Messages */}
                         {writeStatus === 'success' && (
                             <div className="bg-emerald-500/10 dark:bg-emerald-950/30 border border-emerald-500/20 dark:border-emerald-900/50 rounded-xl p-4 flex items-center gap-4 animate-in fade-in zoom-in duration-300">
                                 <CheckCircle2 className="w-8 h-8 text-emerald-500" />
                                 <div className="flex-1">
                                     <p className="font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wide text-xs">Write Successful</p>
                                     <p className="text-[10px] text-emerald-800/50 dark:text-emerald-200/50 mt-1 font-mono">{writeMessage}</p>
                                 </div>
                                 <Button variant="outline" size="sm" onClick={handleBackToScan} className="border-emerald-200 dark:border-emerald-800 text-emerald-600 dark:text-emerald-500 hover:bg-emerald-100 dark:hover:bg-emerald-950 hover:text-emerald-700 dark:hover:text-emerald-400">
                                     NEW TASK
                                 </Button>
                             </div>
                         )}

                         {writeStatus === 'error' && (
                             <div className="bg-red-500/10 dark:bg-red-950/30 border border-red-500/20 dark:border-red-900/50 rounded-xl p-4 flex items-center gap-4 animate-in fade-in zoom-in duration-300">
                                 <XCircle className="w-8 h-8 text-red-500" />
                                 <div>
                                     <p className="font-bold text-red-600 dark:text-red-500 uppercase tracking-wide text-xs">Write Failed</p>
                                     <p className="text-[10px] text-red-800/50 dark:text-red-200/50 mt-1 font-mono">{writeMessage}</p>
                                 </div>
                             </div>
                         )}
                     </div>
                </div>
            )}
        </div>
    </div>
  );
};

