import React from 'react';
import { Minus, Plus } from 'lucide-react';

interface StepperProps {
  value: number;
  onChange: (value: number) => void;
  min?: number;
  max?: number;
  step?: number;
  disabled?: boolean;
}

export const Stepper: React.FC<StepperProps> = ({
  value,
  onChange,
  min = 0,
  max = 100,
  step = 1,
  disabled = false,
}) => {
  const handleIncrement = () => {
    if (disabled) return;
    const newValue = Math.min(max, value + step);
    onChange(newValue);
  };

  const handleDecrement = () => {
    if (disabled) return;
    const newValue = Math.max(min, value - step);
    onChange(newValue);
  };

  return (
    <div className="flex items-center justify-between bg-slate-100 dark:bg-zinc-900 p-1 rounded-full border border-slate-200 dark:border-zinc-800 h-12">
      <button
        onClick={handleDecrement}
        disabled={disabled || value <= min}
        className="w-12 h-full flex items-center justify-center text-slate-400 dark:text-zinc-400 hover:text-slate-800 dark:hover:text-white rounded-full hover:bg-slate-200 dark:hover:bg-zinc-800 disabled:opacity-50 active:scale-90 transition-all"
      >
        <Minus size={16} />
      </button>
      <div className="flex-1 text-center font-mono text-lg font-bold text-slate-800 dark:text-white">
        {value}
      </div>
      <button
        onClick={handleIncrement}
        disabled={disabled || value >= max}
        className="w-12 h-full flex items-center justify-center text-slate-400 dark:text-zinc-400 hover:text-slate-800 dark:hover:text-white rounded-full hover:bg-slate-200 dark:hover:bg-zinc-800 disabled:opacity-50 active:scale-90 transition-all"
      >
        <Plus size={16} />
      </button>
    </div>
  );
};

