import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutGrid, ScrollText, Database, Bluetooth, Cpu, Sun, Moon } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { Logo } from './components/ui/Logo';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

type AppView = 'scanner' | 'writer';
type Theme = 'light' | 'dark';

const ThemeToggle: React.FC<{ theme: Theme, toggleTheme: () => void }> = ({ theme, toggleTheme }) => (
    <button 
        onClick={toggleTheme}
        className="flex flex-col items-center justify-center gap-2 p-3 rounded-2xl w-full text-slate-500 dark:text-zinc-500 hover:text-slate-800 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-zinc-800 transition-all duration-300"
    >
        {theme === 'light' ? <Moon size={22} strokeWidth={1.5} /> : <Sun size={22} strokeWidth={1.5} />}
        <span className="text-[9px] font-bold tracking-widest uppercase">{theme === 'light' ? 'Dark' : 'Light'}</span>
    </button>
);


function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');
  const [theme, setTheme] = useState<Theme>('light');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Theme Management ---
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;
    // Default to light theme if no preference is saved, ignoring system settings.
    const initialTheme = savedTheme || 'light';
    setTheme(initialTheme);
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Logic ---
  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);
        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = { epc: data.epc, timestamp: Date.now(), rssi: data.rssi, count: 1 };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }
    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));
    if (data.cmd === 'WE') {
      if (data.status === 'ok') { setWriteStatus('success'); setWriteMessage(`Encoded: ${data.epc}`); addLog(`Encode Success: ${data.epc}`, 'info'); } 
      else { setWriteStatus('error'); setWriteMessage('Encoding failed. Check log.'); addLog('Encode Failed.', 'error'); }
    }
  }, [addLog]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 150 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        setTags(allTags.slice(0, 500));
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setIsScanning(false); };
  const handleStartScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'S' : 'SB' }); setIsScanning(true); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleStopScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'X' : 'XB' }); if (scanMode === ScanMode.BATCH) setTimeout(() => bleService.requestFileTransfer(), 500); setIsScanning(false); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleRequestBatchFile = async () => { if (!isTransferring) { setFileContent(''); await bleService.requestFileTransfer(); } };
  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    if (key === 'frequency') cmd = { cmd: 'SF', val: value };
    if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
    if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
    await bleService.sendCommand(cmd);
  };
  const handleWriteEpc = async (oldEpc: string, newEpc: string) => { setWriteStatus('pending'); setWriteMessage(''); try { await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc }); } catch (e: any) { setWriteStatus('error'); setWriteMessage(e.message); } };
  const handleClearLog = () => { tagBufferRef.current.clear(); setTags([]); };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // --- Brand Logo Component ---
  const BrandLogo = () => (
    <div className="flex items-center gap-3 select-none">
        <Logo className="w-8 h-8 text-slate-900 dark:text-white" />
        <div className="flex flex-col justify-center h-full">
            <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white leading-none font-sans">
                Next<span className="text-cyan-400">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex bg-slate-50 dark:bg-black text-slate-800 dark:text-zinc-100 font-sans">

      {/* --- DESKTOP DOCK (Left Rail - Glass) --- */}
      <nav className="hidden lg:flex flex-col w-24 bg-white/60 dark:bg-zinc-900/60 backdrop-blur-md border-r border-slate-200 dark:border-zinc-800 items-center py-8 z-30 shadow-2xl">
         <div className="mb-12">
            <div className="w-12 h-12 bg-slate-200/80 dark:bg-zinc-800/80 rounded-2xl flex items-center justify-center border border-slate-300/50 dark:border-zinc-700/50 shadow-[0_0_20px_rgba(0,0,0,0.1)] dark:shadow-[0_0_20px_rgba(0,0,0,0.5)]">
                <Logo className="w-7 h-7 text-slate-800 dark:text-white" />
            </div>
         </div>

         <div className="flex flex-col gap-6 w-full px-4">
            <button 
                onClick={() => setActiveView('scanner')}
                className={`flex flex-col items-center gap-2 p-3 rounded-2xl transition-all duration-300 ${activeView === 'scanner' ? 'bg-slate-900 text-white dark:bg-white dark:text-zinc-950 shadow-lg dark:shadow-[0_0_15px_rgba(255,255,255,0.2)]' : 'text-slate-500 dark:text-zinc-500 hover:text-slate-900 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-zinc-800'}`}
            >
                <LayoutGrid size={22} strokeWidth={1.5} />
                <span className="text-[9px] font-bold tracking-widest uppercase">Dash</span>
            </button>

            <button 
                onClick={() => setActiveView('writer')}
                className={`flex flex-col items-center gap-2 p-3 rounded-2xl transition-all duration-300 ${activeView === 'writer' ? 'bg-slate-900 text-white dark:bg-white dark:text-zinc-950 shadow-lg dark:shadow-[0_0_15px_rgba(255,255,255,0.2)]' : 'text-slate-500 dark:text-zinc-500 hover:text-slate-900 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-zinc-800'}`}
            >
                <Cpu size={22} strokeWidth={1.5} />
                <span className="text-[9px] font-bold tracking-widest uppercase">Write</span>
            </button>
         </div>

         <div className="mt-auto flex flex-col gap-4 items-center w-full px-4">
             <ThemeToggle theme={theme} toggleTheme={toggleTheme} />
             <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_10px_#10b981]' : 'bg-red-500 shadow-[0_0_10px_#ef4444]'}`} title={status}></div>
         </div>
      </nav>

      {/* --- MAIN STAGE --- */}
      <div className="flex-1 flex flex-col relative overflow-hidden bg-gradient-to-br from-slate-100 via-slate-50 to-white dark:from-zinc-950 dark:via-zinc-950 dark:to-[#050505]">

        {/* Mobile Header */}
        <div className="lg:hidden h-16 bg-white/80 dark:bg-zinc-900/80 backdrop-blur flex items-center justify-between px-4 border-b border-slate-200 dark:border-zinc-800 z-20">
            <BrandLogo />
            <div className="flex items-center gap-3">
                 <div className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : 'bg-red-500 shadow-[0_0_8px_#ef4444]'}`} />
                 <button onClick={toggleTheme} className="p-2 text-slate-500">
                    {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
                 </button>
                 <Button size="sm" variant={isConnected ? "danger" : "primary"} onClick={isConnected ? handleDisconnect : handleConnect}>
                    <Bluetooth size={16} />
                 </Button>
            </div>
        </div>

        {/* Content Wrapper */}
        <div className="flex-1 overflow-hidden relative p-0 lg:p-6 lg:gap-6 flex flex-col">

            {activeView === 'scanner' && (
                <div className="w-full h-full flex flex-col lg:flex-row gap-0 lg:gap-6">
                    {/* LEFT: Controls (Vehicle Status) */}
                    <div className={`
                        ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[360px] shrink-0 bg-white/40 dark:bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border-slate-200 dark:border-zinc-800/60 lg:border overflow-hidden shadow-lg dark:shadow-2xl
                    `}>
                        <Controls 
                            status={status}
                            scanMode={scanMode}
                            isScanning={isScanning}
                            settings={settings}
                            onConnect={handleConnect}
                            onDisconnect={handleDisconnect}
                            onToggleMode={setScanMode}
                            onStartScan={handleStartScan}
                            onStopScan={handleStopScan}
                            onUpdateSettings={handleUpdateSettings}
                        />
                    </div>

                    {/* CENTER: Data Visualization (Flight Recorder) */}
                    <div className={`
                        ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                        lg:flex flex-col flex-1 bg-white/40 dark:bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border-slate-200 dark:border-zinc-800/60 lg:border overflow-hidden min-w-0 shadow-lg dark:shadow-2xl
                    `}>
                        <InteractiveLog 
                            tags={tags}
                            onClear={handleClearLog}
                            onSelectEpc={setSelectedEpc}
                            logs={logs}
                        />
                    </div>

                    {/* RIGHT: Batch (Console) */}
                    <div className={`
                        ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[320px] shrink-0 bg-white/40 dark:bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border-slate-200 dark:border-zinc-800/60 lg:border overflow-hidden shadow-lg dark:shadow-2xl
                    `}>
                        <BatchResults 
                            fileContent={fileContent}
                            isTransferring={isTransferring}
                            transferProgress={transferProgress} 
                            onRequestFile={handleRequestBatchFile}
                        />
                    </div>
                </div>
            )}

            {activeView === 'writer' && (
                <div className="w-full h-full bg-white/40 dark:bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border-slate-200 dark:border-zinc-800/60 lg:border overflow-hidden shadow-lg dark:shadow-2xl">
                    <WriterView 
                        onWrite={handleWriteEpc}
                        writeStatus={writeStatus}
                        writeMessage={writeMessage}
                        setWriteStatus={setWriteStatus}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        isScanning={isScanning}
                        liveTags={tags}
                    />
                </div>
            )}

        </div>

        {/* Mobile Tab Bar */}
        {activeView === 'scanner' && (
            <div className="lg:hidden h-20 bg-white/90 dark:bg-zinc-950 border-t border-slate-200 dark:border-zinc-800 flex justify-around items-center z-20 pb-4 backdrop-blur-sm">
                <button onClick={() => setMobileTab('controls')} className={mobileTab === 'controls' ? 'text-slate-900 dark:text-white' : 'text-slate-400 dark:text-zinc-600'}>
                    <LayoutGrid size={24} />
                </button>
                <button onClick={() => setMobileTab('logs')} className={mobileTab === 'logs' ? 'text-slate-900 dark:text-white' : 'text-slate-400 dark:text-zinc-600'}>
                    <ScrollText size={24} />
                </button>
                <button onClick={() => setMobileTab('results')} className={mobileTab === 'results' ? 'text-slate-900 dark:text-white' : 'text-slate-400 dark:text-zinc-600'}>
                    <Database size={24} />
                </button>
            </div>
        )}

      </div>
    </div>
  );
}

